import React, { useState, useEffect } from 'react';

const LoadingScreen: React.FC = () => {
  const [step, setStep] = useState(0);

  useEffect(() => {
    const intervals = [800, 800, 1000, 1500];
    let currentStep = 0;

    const sequence = () => {
      if (currentStep < intervals.length) {
        setTimeout(() => {
          setStep(prev => prev + 1);
          currentStep++;
          sequence();
        }, intervals[currentStep]);
      }
    };

    sequence();
  }, []);

  return (
    <div className="fixed inset-0 z-[100] bg-[#010009] flex items-center justify-center cursor-wait overflow-hidden font-mono">
      <div className="absolute inset-0 z-10 pointer-events-none crt-overlay opacity-80"></div>
      <div className="absolute inset-0 z-10 pointer-events-none animate-monitor-flicker bg-white/5 mix-blend-overlay opacity-5"></div>

      <div className="relative z-20 w-[90%] max-w-2xl bg-[#050A14]/95 border-2 border-cyan-400 shadow-[0_0_40px_rgba(34,211,238,0.2)] p-8 md:p-12 rounded-sm backdrop-blur-sm animate-monitor-flicker">
        <div className="absolute top-0 left-0 w-full h-[1px] bg-cyan-400 shadow-[0_0_15px_#22d3ee]"></div>

        <div className="space-y-4 mb-12 min-h-[160px]">
          {step >= 1 && (
            <div className="flex items-center gap-3 text-green-500/90 text-sm md:text-base font-medium tracking-wide">
              <span className="opacity-50">SYS.BOOT</span>
              <span>&gt; BOOTING CAPY-OS...</span>
              <span className="ml-auto text-green-400 font-bold">[ OK ]</span>
            </div>
          )}
          {step >= 2 && (
            <div className="flex items-center gap-3 text-green-500/90 text-sm md:text-base font-medium tracking-wide">
              <span className="opacity-50">SYS.INIT</span>
              <span>&gt; INITIALIZING STARFIELD...</span>
              <span className="ml-auto text-green-400 font-bold">[ OK ]</span>
            </div>
          )}
          {step >= 3 && (
            <div className="flex items-center gap-3 text-amber-500 text-sm md:text-base font-medium tracking-wide">
              <span className="opacity-50">NET.SECURE</span>
              <span>&gt; ESTABLISHING SECURE CONNECTION...</span>
            </div>
          )}
          {step >= 4 && (
            <div className="pt-6 flex items-center gap-1 text-cyan-400 text-lg md:text-xl font-bold tracking-wider drop-shadow-[0_0_8px_rgba(34,211,238,0.6)]">
              <span>&gt; WELCOME TO CAPYPAGES</span>
              <span className="animate-cursor-blink text-cyan-400">_</span>
